    s_togglePin_lastPinIndex = 0;
    s_setPinMode_lastPinIndex = 0;
    s_setPinMode_lastMode = 0;
    s_setPinModeLVDS_lastPinIndex = 0;
    s_setPinModeLVDS_lastPinMode = 0;
}

