    if (config != NULL_PTR)
    {
        /* Pattern D: capture selected config fields */
        s_init_lastFrequency   = config->frequency;
        s_init_lastNumChannels = config->numChannels;
        s_init_lastAlignment   = (uint32)config->alignment;
